/**
 * @name Validate-then-normalize anti-pattern (check before canonicalization)
 * @description Path validation using startsWith occurs before normalization - bypass possible
 * @kind path-problem
 * @problem.severity error
 * @id java/sling-validate-then-normalize
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-706
 */

import java
import semmle.code.java.dataflow.DataFlow

module ValidateThenNormalizeConfig implements DataFlow::ConfigSig {
  // Source: the result of a startsWith check (i.e., the value that was checked)
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall startsWithCall |
      startsWithCall.getMethod().hasName("startsWith") and
      startsWithCall.getMethod().getDeclaringType().hasQualifiedName("java.lang", "String") and
      source.asExpr() = startsWithCall.getQualifier()
    )
  }

  // Sink: the argument of a normalize/resolve call
  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall normalizeCall |
      (normalizeCall.getMethod().hasName("normalize") or
       normalizeCall.getMethod().hasName("cleanPath") or
       normalizeCall.getMethod().hasName("getCanonicalPath")) and
      (sink.asExpr() = normalizeCall.getQualifier() or
       sink.asExpr() = normalizeCall.getAnArgument())
    )
  }
}

module ValidateThenNormalizeFlow = DataFlow::Global<ValidateThenNormalizeConfig>;
import ValidateThenNormalizeFlow::PathGraph

from ValidateThenNormalizeFlow::PathNode source, ValidateThenNormalizeFlow::PathNode sink
where ValidateThenNormalizeFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path validated with startsWith at $@ BEFORE normalization - traversal sequences like '../' may bypass the check.", source.getNode(), "startsWith check"

/**
 * @name Full taint path: HTTP input -> startsWith check -> normalize -> resource load in SlingScriptResolverImpl
 * @description Traces complete path from external input through validate-then-normalize to resource loading
 * @kind path-problem
 * @problem.severity error
 * @id java/sling-script-resolver-full-path
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-706
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ScriptResolverConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
    or
    // Parameters to SlingScriptResolverImpl methods
    exists(Method m, Parameter p |
      m.getDeclaringType().hasName("SlingScriptResolverImpl") and
      p = m.getAParameter() and
      source.asParameter() = p
    )
    or
    // Parameters to ScriptResourceResolver methods
    exists(Method m, Parameter p |
      m.getDeclaringType().hasName("ScriptResourceResolver") and
      p = m.getAParameter() and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Resource resolution calls after normalize
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResource", "resolve", "getResourceAsStream", "getEntry"]) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // ClassLoader resource loading
    exists(MethodCall mc |
      mc.getMethod().hasName(["getResource", "getResourceAsStream"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ScriptResolverFlow = TaintTracking::Global<ScriptResolverConfig>;
import ScriptResolverFlow::PathGraph

from ScriptResolverFlow::PathNode source, ScriptResolverFlow::PathNode sink
where ScriptResolverFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Input flows from $@ to resource loading operation - potential path traversal after validate-then-normalize.", source.getNode(), "input parameter"
